calcFn:
var reach = wingspan / 2;
    var oppReach = oppWingspan / 2;
    var apeIndex = wingspan - height;
    var oppApe = oppWingspan - oppHeight;
    var advantage = wingspan - oppWingspan;
    var strategy;
    if (advantage > 3) strategy = 'Strong reach advantage — fight at distance, use jabs and straight punches';
    else if (advantage > 0) strategy = 'Slight reach advantage — mix distance fighting with combinations';
    else if (advantage > -3) strategy = 'Similar reach — versatile approach, focus on timing and footwork';
    else strategy = 'Reach disadvantage — work inside, cut angles, use body shots and hooks';
    document.getElementById('reach').textContent = fmt(reach, 1) + '" (' + fmt(wingspan, 1) + '" wingspan)';
    document.getElementById('apeIndex').textContent = (apeIndex >= 0 ? '+' : '') + fmt(apeIndex, 1) + '" (avg is 0, positive is advantageous)';
    document.getElementById('reachAdvantage').textContent = (advantage >= 0 ? '+' : '') + fmt(advantage, 1) + '" over opponent';
    document.getElementById('optimalRange').textContent = strategy;

var effort = parseFloat(effort);
    var watts = ftp * effort;
    var weightKg = weight * 0.4536;
    var riderKg = weightKg * 0.88;
    var wpk = watts / riderKg;
    var gravForce = weightKg * 9.81 * (gradient / 100);
    var rollingR = weightKg * 9.81 * 0.005;
    var speedMs = watts / (gravForce + rollingR);
    var speedKmh = speedMs * 3.6;
    var speedMph = speedKmh / 1.609;
    var cat;
    if (wpk >= 5.5) cat = 'Professional / World Tour level';
    else if (wpk >= 4.5) cat = 'Cat 1 / Elite amateur';
    else if (wpk >= 3.8) cat = 'Cat 2 / Strong amateur';
    else if (wpk >= 3.2) cat = 'Cat 3 / Club racer';
    else if (wpk >= 2.5) cat = 'Cat 4 / Recreational cyclist';
    else cat = 'Beginner / Casual rider';
    document.getElementById('power').textContent = fmt(watts, 0) + ' watts at ' + fmt(effort * 100, 0) + '% FTP';
    document.getElementById('wpk').textContent = fmt(wpk, 2) + ' W/kg';
    document.getElementById('climbSpeed').textContent = fmt(speedMph, 1) + ' mph (' + fmt(speedKmh, 1) + ' km/h) on ' + gradient + '% grade';
    document.getElementById('category').textContent = cat;

var stickLen = parseInt(stickLength);
    var armSpd = parseInt(armSpeed);
    var techFactor = parseFloat(technique);
    var leverFactor = stickLen / 42;
    var strengthFactor = Math.pow(weight / 180, 0.3);
    var baseSpeed = 110;
    var shotMph = baseSpeed * (armSpd / 100) * techFactor * leverFactor * strengthFactor;
    var shotMs = shotMph * 0.4470;
    var ballMass = 0.142;
    var ke = 0.5 * ballMass * shotMs * shotMs;
    var distanceM = 15 * 0.9144;
    var reactionTime = distanceM / shotMs;
    var comparison;
    if (shotMph >= 100) comparison = 'Pro-level speed. Comparable to professional lacrosse.';
    else if (shotMph >= 85) comparison = 'College-level speed. Very competitive.';
    else if (shotMph >= 70) comparison = 'High school varsity level.';
    else comparison = 'Developing player. Focus on technique and core strength.';
    document.getElementById('shotSpeed').textContent = fmt(shotMph, 0) + ' mph (' + fmt(shotMph * 1.609, 0) + ' km/h)';
    document.getElementById('kineticEnergy').textContent = fmt(ke, 1) + ' joules';
    document.getElementById('reactionTime').textContent = fmt(reactionTime * 1000, 0) + ' ms from 15 yards';
    document.getElementById('comparison').textContent = comparison;

var avgYields = {corn: 175, soybeans: 50, wheat: 47, rice: 7500, cotton: 800};
    var units = {corn: 'bu', soybeans: 'bu', wheat: 'bu', rice: 'lbs', cotton: 'lbs'};
    var baseYield = avgYields[crop];
    var unit = units[crop];
    var actualYield = baseYield * (yieldFactor / 100);
    var total = actualYield * acres;
    var revenue = total * pricePerUnit;
    var revPerAcre = revenue / acres;
    document.getElementById('yieldPerAcre').textContent = fmt(actualYield, 1) + ' ' + unit + '/acre';
    document.getElementById('totalYield').textContent = fmt(total, 0) + ' ' + unit;
    document.getElementById('grossRevenue').textContent = dollar(revenue);
    document.getElementById('revenuePerAcre').textContent = dollar(revPerAcre) + '/acre';

var dailyLbs = {beef: 26, dairy: 45, hog: 7, chicken: 0.25, sheep: 4};
    var daily = dailyLbs[animal];
    var dailyTotal = daily * headCount;
    var totalLbs = dailyTotal * numDays;
    var totalTons = totalLbs / 2000;
    var cost = totalTons * feedCost;
    var costPerHead = cost / headCount;
    document.getElementById('dailyPerHead').textContent = fmt(daily, 2) + ' lbs/day';
    document.getElementById('dailyTotal').textContent = fmt(dailyTotal, 0) + ' lbs/day (' + fmt(dailyTotal / 2000, 2) + ' tons)';
    document.getElementById('totalFeed').textContent = fmt(totalTons, 1) + ' tons (' + fmt(totalLbs, 0) + ' lbs)';
    document.getElementById('totalCost').textContent = dollar(cost) + ' total (' + dollar(costPerHead) + '/head)';

var revenue = grossRevenue * acres;
    var costsPerAcre = seedCost + fertCost + chemCost + machineCost + landCost + insuranceCost;
    var totalCosts = costsPerAcre * acres;
    var profit = revenue - totalCosts;
    var profitPA = profit / acres;
    var breakEvenYield = costsPerAcre / 4.5;
    document.getElementById('totalRevenue').textContent = dollar(revenue);
    document.getElementById('totalCosts').textContent = dollar(totalCosts) + ' (' + dollar(costsPerAcre) + '/acre)';
    document.getElementById('netProfit').textContent = (profit >= 0 ? '' : '-') + dollar(Math.abs(profit));
    document.getElementById('profitPerAcre').textContent = (profitPA >= 0 ? '' : '-') + dollar(Math.abs(profitPA)) + '/acre';
    document.getElementById('breakeven').textContent = fmt(breakEvenYield, 0) + ' bu/acre';

var weightLbs = bulletWeight / 7000;
    var energy = (bulletWeight * velocity * velocity) / 450240;
    var momentum = weightLbs * velocity;
    var pf = (bulletWeight * velocity) / 1000;
    var tko = (bulletWeight * velocity * bulletDia) / 7000;
    document.getElementById('energy').textContent = fmt(energy, 0) + ' ft-lbs (' + fmt(energy * 1.356, 0) + ' joules)';
    document.getElementById('momentum').textContent = fmt(momentum, 2) + ' lb·ft/s';
    document.getElementById('powerFactor').textContent = fmt(pf, 1) + (pf >= 165 ? ' (Major)' : pf >= 125 ? ' (Minor)' : ' (Below minimum)');
    document.getElementById('taylorKO').textContent = fmt(tko, 1);

var chokePct = parseFloat(choke);
    var pelletsPerOz = {'9':585,'8':410,'7.5':350,'6':225,'4':135,'2':90,'00':8};
    var ppo = pelletsPerOz[shotSize] || 350;
    var totalPellets = shotSize === '00' ? Math.round(8 * loadOz / 1.125) : Math.round(ppo * loadOz);
    var spreadInches = distance * 1.0 * (1 - chokePct) * 3 + 10;
    if (distance <= 10) spreadInches = 8 + distance * 0.5;
    var circleArea = Math.PI * 15 * 15;
    var patternArea = Math.PI * Math.pow(spreadInches / 2, 2);
    var inCircle = Math.round(totalPellets * chokePct * Math.min(1, circleArea / patternArea));
    inCircle = Math.min(inCircle, totalPellets);
    var density = inCircle / circleArea;
    document.getElementById('spreadDia').textContent = fmt(spreadInches, 0) + '" diameter at ' + distance + ' yards';
    document.getElementById('pelletCount').textContent = fmt(totalPellets, 0) + ' pellets';
    document.getElementById('inCircle').textContent = fmt(inCircle, 0) + ' pellets (' + fmt(inCircle / totalPellets * 100, 0) + '% in 30" circle)';
    document.getElementById('density').textContent = fmt(density, 2) + ' pellets per sq inch';

var bulletLbs = bulletWeight / 7000;
    var chargeLbs = chargeWeight / 7000;
    var gasVelocity = muzzleVelocity * 1.75;
    var recoilVel = ((bulletLbs * muzzleVelocity) + (chargeLbs * gasVelocity)) / gunWeight;
    var recoilE = (gunWeight * recoilVel * recoilVel) / (2 * 32.174);
    var impulse = gunWeight * recoilVel / 32.174;
    var rating;
    if (recoilE < 8) rating = 'Light — comfortable for all shooters';
    else if (recoilE < 15) rating = 'Moderate — manageable for most shooters';
    else if (recoilE < 25) rating = 'Heavy — noticeable recoil, technique important';
    else if (recoilE < 40) rating = 'Very heavy — experienced shooters only';
    else rating = 'Severe — magnum/dangerous game class';
    document.getElementById('recoilVelocity').textContent = fmt(recoilVel, 1) + ' fps';
    document.getElementById('recoilEnergy').textContent = fmt(recoilE, 1) + ' ft-lbs';
    document.getElementById('recoilImpulse').textContent = fmt(impulse, 2) + ' lb-s';
    document.getElementById('rating').textContent = rating;

var windMs = avgWindSpeed * 0.44704;
    var rotorM = rotorDiameter * 0.3048;
    var area = Math.PI * Math.pow(rotorM / 2, 2);
    var airDensity = 1.225;
    var betzLimit = 0.35;
    var ratedPower = 0.5 * airDensity * area * Math.pow(windMs, 3) * betzLimit;
    var capacityFactor = 0.25;
    var annualKWH = ratedPower * 8760 * capacityFactor / 1000;
    var monthlySav = (annualKWH / 12) * electricRate;
    var annualSav = annualKWH * electricRate;
    var payback = annualSav > 0 ? turbineCost / annualSav : Infinity;
    document.getElementById('ratedPower').textContent = fmt(ratedPower, 0) + ' watts (' + fmt(ratedPower / 1000, 1) + ' kW)';
    document.getElementById('annualOutput').textContent = fmt(annualKWH, 0) + ' kWh/year';
    document.getElementById('monthlySavings').textContent = dollar(monthlySav) + '/month (' + dollar(annualSav) + '/year)';
    document.getElementById('payback').textContent = payback === Infinity ? 'Never' : fmt(payback, 1) + ' years';

var credit = systemCost * (taxCredit / 100);
    var netCost = systemCost - credit;
    var geoEfficiency = cop / 1.0;
    var geoBill = currentBill / geoEfficiency;
    var savings = currentBill - geoBill;
    var payback = savings > 0 ? netCost / savings : Infinity;
    var twentyYear = (savings * 20) - netCost;
    document.getElementById('netCost').textContent = dollar(netCost) + ' (after ' + dollar(credit) + ' tax credit)';
    document.getElementById('annualSavings').textContent = dollar(savings) + '/year (' + fmt(savings / currentBill * 100, 0) + '% reduction)';
    document.getElementById('payback').textContent = payback === Infinity ? 'N/A' : fmt(payback, 1) + ' years';
    document.getElementById('twentyYearSavings').textContent = dollar(twentyYear);

var totalKWH = dailyUsage * autonomyDays;
    var usableKWH = totalKWH / (depthOfDischarge / 100);
    var voltage = parseInt(batteryVoltage);
    var ah = (usableKWH * 1000) / voltage;
    var costPerKWH = {lithium: 400, agm: 200, flooded: 150};
    var lifeYears = {lithium: '10-15 years (5000+ cycles)', agm: '4-6 years (1000 cycles)', flooded: '5-8 years (1500 cycles)'};
    var cost = usableKWH * costPerKWH[batteryType];
    document.getElementById('totalCapacity').textContent = fmt(usableKWH, 1) + ' kWh (' + fmt(totalKWH, 1) + ' kWh usable)';
    document.getElementById('ampHours').textContent = fmt(ah, 0) + ' Ah at ' + voltage + 'V';
    document.getElementById('estimatedCost').textContent = dollar(cost);
    document.getElementById('batteryLife').textContent = lifeYears[batteryType];
